import React, { useContext, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Container } from 'react-bootstrap'; 

// Importaciones de Contextos
import { SettingsContext } from '../context/SettingsContext'; 
// ELIMINADOS: AuthContext, CartContext, SearchBox, Dropdown.

const Header = () => {
  // Solo necesitamos settings para el nombre del sitio
  const { settings } = useContext(SettingsContext); 

  useEffect(() => {
    // Aplicar el color de acento de la configuración a las variables CSS globales
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);
  
  // Usaremos un color más suave que --brand-dark para que se vea como en la imagen de referencia.
  // Este color lo forzamos aquí temporalmente, ya que el archivo index.css define --brand-dark.
  const headerBgColor = '#1C2036'; // Un gris muy oscuro, casi negro, para el Header
  
  return (
    // CRÍTICO: rounded-b-xl para el redondeo inferior grande
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md rounded-b-xl"
      // CRÍTICO: FORZAMOS EL COLOR DE FONDO AJUSTADO y padding
      style={{ 
        backgroundColor: headerBgColor, 
        paddingTop: '1rem', 
        paddingBottom: '1rem' 
      }} 
    >
      <Container> 
        <div className="d-flex justify-content-start align-items-center"> 
          
          {/* 1. Logo de Texto/Eslogan - ESTILOS FINALES */}
          <Link 
            to="/" 
            // no-underline es crucial para quitar el subrayado azul por defecto de los enlaces
            className="flex flex-col items-start h-full no-underline"
          > 
            {/* Nombre: Blanco, grande, negrita, mayúsculas */}
            <span 
              className="text-white text-xl font-extrabold tracking-widest uppercase" 
              style={{ lineHeight: 1 }}
            >
              {settings?.siteName || 'TECNOTITLÁN'}
            </span>
            {/* Eslogan: Gris opaco, pequeño. Corregido el error tipográfico "Raiices" -> "Raíces" */}
            <span 
              className="text-gray-400 text-xs font-light tracking-wide mt-0.5" 
              style={{ lineHeight: 1 }} 
            >
              Tecnología con Raíces
            </span>
          </Link>
          
          {/* Aquí termina el contenido del Header. */}
          
        </div>
      </Container>
    </header>
  );
};

export default Header;
